PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT DISTINCT ?stadium WHERE {
  ?player rdfs:label 'Hatem Aqel'@en.
  ?match wdt:P31 wd:Q713854; 
         wdt:P2145 'Draw' ;
         wdt:P254 ?stadium.
  ?match wdt:P195 ?player.
}

